/// Look up a breed by its `compat:breedId`. Real behavior, not a static
/// table dump: this is the "zero handler gap" seam other packs' generated
/// code (or hand-written code in a consumer crate) can call directly.
pub fn lookup_breed(id: &str) -> Option<&'static Breed> {
    BREEDS.iter().find(|b| b.id == id)
}

/// Look up an algorithm by its `pi:algorithmId`.
pub fn lookup_algorithm(id: &str) -> Option<&'static Algorithm> {
    ALGORITHMS.iter().find(|a| a.id == id)
}

/// All algorithms in a given `pi:category`, in `ALGORITHMS` order.
pub fn algorithms_by_category(category: &str) -> Vec<&'static Algorithm> {
    ALGORITHMS.iter().filter(|a| a.category == category).collect()
}

/// Count of admitted breeds -- independently derived (via `BREEDS.len()`)
/// from the same graph the markdown registry's own header-count row
/// summarizes, letting a proof cross-check the two without either being the
/// other's oracle.
pub fn breed_count() -> usize {
    BREEDS.len()
}

/// Count of admitted algorithms.
pub fn algorithm_count() -> usize {
    ALGORITHMS.len()
}
